import { decrypt, encrypt } from '@utils/encryption.util';

describe('encryption.util', () => {
	const key = 'a'.repeat(32);

	describe('encrypt', () => {
		it('should return a string', () => {
			const result = encrypt({ plaintext: 'hello', key });
			expect(typeof result).toBe('string');
		});

		it('should produce different ciphertexts for the same plaintext', () => {
			const first = encrypt({ plaintext: 'hello', key });
			const second = encrypt({ plaintext: 'hello', key });
			expect(first).not.toBe(second);
		});
	});

	describe('decrypt', () => {
		it('should return the original plaintext after encrypt + decrypt', () => {
			const plaintext = 'my secret value';
			const ciphertext = encrypt({ plaintext, key });
			const result = decrypt({ ciphertext, key });
			expect(result).toBe(plaintext);
		});

		it('should throw when given garbage input', () => {
			expect(() => decrypt({ ciphertext: 'not-valid-base64url!!', key })).toThrow();
		});
	});
});

import { createCipheriv, createDecipheriv, randomBytes } from 'node:crypto';

const ALGORITHM = 'aes-256-gcm';
const IV_LENGTH = 16;
const AUTH_TAG_LENGTH = 16;

export const encrypt = ({
	plaintext,
	key,
}: {
	plaintext: string;
	key: string;
}): string => {
	const iv = randomBytes(IV_LENGTH);
	const cipher = createCipheriv(ALGORITHM, key, iv, { authTagLength: AUTH_TAG_LENGTH });
	const encrypted = Buffer.concat([cipher.update(plaintext, 'utf8'), cipher.final()]);
	const authTag = cipher.getAuthTag();
	return Buffer.concat([iv, authTag, encrypted]).toString('base64url');
};

export const decrypt = ({
	ciphertext,
	key,
}: {
	ciphertext: string;
	key: string;
}): string => {
	const data = Buffer.from(ciphertext, 'base64url');
	const iv = data.subarray(0, IV_LENGTH);
	const authTag = data.subarray(IV_LENGTH, IV_LENGTH + AUTH_TAG_LENGTH);
	const encrypted = data.subarray(IV_LENGTH + AUTH_TAG_LENGTH);
	const decipher = createDecipheriv(ALGORITHM, key, iv, {
		authTagLength: AUTH_TAG_LENGTH,
	});
	decipher.setAuthTag(authTag);
	return Buffer.concat([decipher.update(encrypted), decipher.final()]).toString('utf8');
};
